const raw = $input.first().json.output || '';
const match = raw.match(/\{[\s\S]*\}/);
let parsed = { what_they_do: '', why_they_fit: '', specific_hook: '' };
try { parsed = JSON.parse(match ? match[0] : raw); } catch (e) {}
return [{ json: { output: parsed } }];
